8	import Foundation
9	
10	extension Array where Array.Element == UInt8 {
11	
12	    func toBinaryInteger<T: FixedWidthInteger>(start: Int) -> T {
13	        var collectedBytes: [Element] = []
14	
15	        let length = T.bitWidth / 8
16	
17	        for index in start..<start + length where index < count {
18	            collectedBytes.append(self[index])
19	        }
20	
21	        return collectedBytes.withUnsafeBytes { pointer in
22	            UnsafeRawPointer(pointer.baseAddress!).load(as: T.self)
23	        }
24	    }
25	    
26	    func toFloat(start: Int) -> Float32 {
27	        var bytes: [UInt8] = []
28	        let floatSize = 4
29	
30	        for index in start..<start + floatSize where index < count {
31	            bytes.append(self[index])
32	        }
33	        var floatValue: Float32 = 0.0
34	        memcpy(&floatValue, bytes, floatSize)
35	        
36	        return floatValue
37	    }
38	}
39	
40	extension Array {
41	    func chunks(by size: Int) -> [[Element]] {
42	        stride(from: 0, to: count, by: size).map {
43	            Array(self[$0 ..< Swift.min($0 + size, count)])
44	        }
45	    }
46	}
47	
48	extension String {
49	    func components(withLength length: Int) -> [String] {
50	        stride(from: 0, to: count, by: length).map {
51	            let start = index(startIndex, offsetBy: $0)
52	            let end = index(start, offsetBy: length, limitedBy: endIndex) ?? endIndex
53	            return String(self[start..<end])
54	        }
55	    }
56	}
57	
58	extension Array where Element: Hashable {
59	    func difference(from other: [Element]) -> [Element] {
60	        let thisSet = Set(self)
61	        let otherSet = Set(other)
62	        return Array(thisSet.symmetricDifference(otherSet))
63	    }
64	}
65	
66	extension Array where Element: Equatable {
67	    subscript(safe bounds: Range<Int>) -> ArraySlice<Element> {
68	        if bounds.lowerBound > count { return [] }
69	        let lower = Swift.max(0, bounds.lowerBound)
70	        let upper = Swift.max(0, Swift.min(count, bounds.upperBound))
71	        return self[lower..<upper]
72	    }
73	}
74	
75	extension Array where Element: Comparable {
76	    mutating func insertSorted(_ newElement: Element) {
77	        if isEmpty {
78	            append(newElement)
79	            return
80	        }
81	        
82	        if let last, last < newElement {
83	            append(newElement)
84	            return
85	        }
86	        
87	        var low = 0
88	        var high = count - 1
89	        
90	        while low <= high {
91	            let mid = low + (high - low) / 2
92	            if self[mid] == newElement {
93	                self.insert(newElement, at: mid)
94	                return
95	            } else if self[mid] < newElement {
96	                low = mid + 1
97	            } else {
98	                high = mid - 1
99	            }
100	        }
101	        insert(newElement, at: low)
102	    }
103	}
104	
105	extension Array where Element: Numeric {
106	    func trimArray() -> [Element] {
107	        var trimmedArray = self
108	        while trimmedArray.last == 0 {
109	            trimmedArray.removeLast()
110	        }
111	        return trimmedArray
112	    }
113	    
114	    func fillZeroArray(count: Int) -> [Element] {
115	        self + Array(repeating: 0, count: Swift.max(0, count - self.count))
116	    }
117	}
118	
119	extension Array: @retroactive Identifiable where Element: Hashable {
120	   public var id: Self { self }
121	}
122	
123	extension Numeric {
124	    
125	    var asBytes: [UInt8] {
126	        withUnsafeBytes(of: self) { Array($0) }
127	    }
128	}
