8	import Foundation
9	
10	/// Чтение очередной порции спектра
11	struct SpectrumDiffCommand: BluetoothCommand {
12	    
13	    /// Формат Спектра
14	    let specFormatVersion: Bool
15	    
16	    let request = BluetoothCommandRequest(
17	        type: .readVirtualString,
18	        command: .spectrumDiff
19	    )
20	}
21	
22	// MARK: - Response
23	
24	extension SpectrumDiffCommand {
25	    
26	    private enum Consts {
27	        static let defaultOffset = 1
28	        static let maxSpectrumChannels = 1024
29	        static let zipSpectrumChannels = 256
30	        static let dataSize = (defaultOffset + maxSpectrumChannels) * 4
31	        static let dataSize256 = (defaultOffset + zipSpectrumChannels) * 4
32	    }
33	    
34	    struct Response: Equatable {
35	        let time: UInt32
36	        let countNeg: UInt32?
37	        let pulses: [UInt32]
38	        
39	        var isValid: Bool {
40	            time > 0 && pulses.contains { $0 > 0 }
41	        }
42	    }
43	    
44	    var response: BluetoothCommandResponseBuilder<Response> {
45	        .init { storage in
46	            let bytes = storage.body
47	            let time: UInt32 = bytes.toBinaryInteger(start: 0)
48	            var countNeg: UInt32?
49	            var pulses: [UInt32] = []
50	            if specFormatVersion {
51	                countNeg = bytes.toBinaryInteger(start: 4)
52	                pulses = try SpectrumPulseConverter.spectrumZip(bytes: Array(bytes.dropFirst(8)))
53	            } else {
54	                if bytes.count == Consts.dataSize {
55	                    for index in 0..<Consts.dataSize {
56	                        pulses[index] = bytes.toBinaryInteger(start: (Consts.defaultOffset + index) * 4)
57	                    }
58	                } else if bytes.count == Consts.dataSize256 {
59	                    /// Парсинг данного спектра не актуален и не работает
60	                }
61	            }
62	
63	            let spectrum = Response(
64	                time: time,
65	                countNeg: countNeg,
66	                pulses: pulses
67	            )
68	
69	            return spectrum
70	        }
71	    }
72	}
